#include <stdio.h>
#include <stdint.h>
#include <limits.h>

#define MAX_N 20
#define MAX_M 400

int min(int a, int b) { return a < b ? a : b; }

int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int u, v, Pu_v;
        int graph[MAX_N][MAX_N] = {{0}};
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &u, &v, &Pu_v);
            graph[u][v] = graph[v][u] = Pu_v;
        }
        int min_power = INT_MAX;
        for (int mask = 0; mask < (1 << (2 * N)); mask++) {
            int power = 0;
            int valid = 1;
            for (int i = 0; i < 2 * N; i++) {
                if ((mask & (1 << i)) == 0) continue;
                int count = 0;
                for (int j = 0; j < 2 * N; j++) {
                    if ((mask & (1 << j)) == 0) continue;
                    if (graph[i][j] > 0) {
                        power += graph[i][j];
                        count++;
                    }
                }
                if ((i % 2 == 0 && count % 2 == 1) || (i % 2 == 1 && count % 2 == 0)) {
                    valid = 0;
                    break;
                }
            }
            if (valid) min_power = min(min_power, power);
        }
        printf("%d\n", min_power);
    }
    return 0;
}

